import{_ as a,o as s,c as n,a2 as e}from"./chunks/framework.TWA1q3r6.js";const u=JSON.parse('{"title":"🧩 3-5Y · 执行功能期","description":"","frontmatter":{"title":"🧩 3-5Y · 执行功能期"},"headers":[],"relativePath":"stages/3-5y.md","filePath":"stages/3-5y.md"}'),o={name:"stages/3-5y.md"};function i(r,t,d,l,h,c){return s(),n("div",null,[...t[0]||(t[0]=[e(`<h1 id="🧩-3-5y-·-执行功能期" tabindex="-1">🧩 3-5Y · 执行功能期 <a class="header-anchor" href="#🧩-3-5y-·-执行功能期" aria-label="Permalink to &quot;🧩 3-5Y · 执行功能期&quot;">​</a></h1><blockquote><p>&quot;爸爸我赢了！&quot;&quot;你耍赖！&quot;&quot;我们再来一局！&quot;</p><p>桌游、运动、户外两小时、和小朋友的江湖 —— 一个小小思想家正在诞生。</p></blockquote><hr><h2 id="🎯-发展里程碑" tabindex="-1">🎯 发展里程碑 <a class="header-anchor" href="#🎯-发展里程碑" aria-label="Permalink to &quot;🎯 发展里程碑&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>科学项目</th><th>在做什么</th><th>每天多久</th><th>来源</th></tr></thead><tbody><tr><td>执行功能</td><td><strong>规则类桌游 / 假装游戏</strong></td><td>等轮次(抑制控制) + 记规则(工作记忆) + 换策略(认知灵活性)</td><td>20-30min/天</td><td>Diamond</td></tr><tr><td>大运动</td><td><strong>结构化运动</strong></td><td>游泳/体操/跳绳 → 系统运动技能 + 心肺发育</td><td>每周2-3次</td><td>AAP</td></tr><tr><td>近视预防</td><td><strong>户外光照暴露</strong></td><td>多巴胺介导巩膜生长抑制 → 户外是近视预防的唯一强因果因素</td><td>每天≥2h</td><td>AAO</td></tr><tr><td>语言/认知</td><td><strong>开放式提问</strong></td><td>&quot;你觉得为什么？&quot; → 推理 + 叙事能力</td><td>融入日常</td><td>—</td></tr><tr><td>社会化</td><td><strong>同伴自由游戏</strong></td><td>合作、协商、冲突解决的真实训练场</td><td>每周多次</td><td>—</td></tr></tbody></table><hr><h2 id="🛡️-装备清单" tabindex="-1">🛡️ 装备清单 <a class="header-anchor" href="#🛡️-装备清单" aria-label="Permalink to &quot;🛡️ 装备清单&quot;">​</a></h2><h3 id="安全必备" tabindex="-1">安全必备 <a class="header-anchor" href="#安全必备" aria-label="Permalink to &quot;安全必备&quot;">​</a></h3><h4 id="🚗-安全座椅-前向-增高垫过渡-essential" tabindex="-1">🚗 安全座椅（前向/增高垫过渡） <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#🚗-安全座椅-前向-增高垫过渡-essential" aria-label="Permalink to &quot;🚗 安全座椅（前向/增高垫过渡） Essential&quot;">​</a></h4><p>体重身高达标前持续使用。从后向转前向，再到增高垫，别急着&quot;毕业&quot;。（AAP/CPSC）</p><p><strong>选购</strong> 沿用 <a href="/linyuhan-baby-guide/stages/0-3m.html">0-3M</a> 阶段购买的座椅，或根据体重升级增高垫：Cybex Solution / Joie Trillo</p><h4 id="⛑️-运动护具-头盔-护膝-essential" tabindex="-1">⛑️ 运动护具（头盔/护膝） <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#⛑️-运动护具-头盔-护膝-essential" aria-label="Permalink to &quot;⛑️ 运动护具（头盔/护膝） Essential&quot;">​</a></h4><p>自行车、滑板车阶段，头部外伤预防是第一位的。从第一次骑就戴上。（CDC）</p><p><strong>选购</strong> micro / Globber / 迪卡侬，¥50-200/套</p><h4 id="👁️-定期视力筛查-essential" tabindex="-1">👁️ 定期视力筛查 <span class="verdict verdict-essential">Essential</span> <a class="header-anchor" href="#👁️-定期视力筛查-essential" aria-label="Permalink to &quot;👁️ 定期视力筛查 Essential&quot;">​</a></h4><p>3-5岁是弱视治疗的窗口期，<strong>错过不可逆</strong>。每年至少一次专业筛查。（AAP）</p><p><strong>选购</strong> 当地三甲医院眼科 / 专业儿童眼科诊所，每年1次</p><h3 id="兴趣启蒙" tabindex="-1">兴趣启蒙 <a class="header-anchor" href="#兴趣启蒙" aria-label="Permalink to &quot;兴趣启蒙&quot;">​</a></h3><h4 id="🏊-结构化运动课-游泳-体操-conditional" tabindex="-1">🏊 结构化运动课（游泳/体操） <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🏊-结构化运动课-游泳-体操-conditional" aria-label="Permalink to &quot;🏊 结构化运动课（游泳/体操） Conditional&quot;">​</a></h4><p>4岁以上可以开始系统学习运动技能。选孩子感兴趣的，不必追求&quot;全面发展&quot;。</p><p><strong>选购</strong> 本地口碑机构，建议先上体验课。游泳/体操/跆拳道/轮滑均可，¥100-300/课</p><h4 id="🎹-乐器启蒙-conditional" tabindex="-1">🎹 乐器启蒙 <span class="verdict verdict-conditional">Conditional</span> <a class="header-anchor" href="#🎹-乐器启蒙-conditional" aria-label="Permalink to &quot;🎹 乐器启蒙 Conditional&quot;">​</a></h4><p>音乐训练与执行功能有相关性，但核心驱动力应该是<strong>兴趣</strong>，不是&quot;开发大脑&quot;。</p><p><strong>选购</strong> 从体验课开始，钢琴/尤克里里/打击乐入门。琴行租琴试学，确认兴趣再买</p><div class="danger custom-block"><p class="custom-block-title">❌ 避坑清单</p><ul><li><strong>防蓝光眼镜（无近视）</strong> — 没有证据蓝光导致儿童近视。近视预防的核心是户外时长（每天2h），不是防蓝光。（AAO）</li><li><strong>&quot;全脑开发&quot;/感统训练（无诊断）</strong> — 无医学诊断的感统训练无RCT。替代：自由玩耍 + 户外 + 桌游</li></ul></div><hr><h2 id="📊-全阶段发展算法速查卡" tabindex="-1">📊 全阶段发展算法速查卡 <a class="header-anchor" href="#📊-全阶段发展算法速查卡" aria-label="Permalink to &quot;📊 全阶段发展算法速查卡&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>0-3M  趴 + 看脸 + 听说话 + 被抱</span></span>
<span class="line"><span>3-6M  翻 + 抓 + 回应对话 + 摸</span></span>
<span class="line"><span>6-12M 爬 + 躲猫猫 + 指认 + 手指食物</span></span>
<span class="line"><span>1-3Y  读 + 跑 + 涂 + 说情绪 + 上厕所</span></span>
<span class="line"><span>3-5Y  桌游 + 运动 + 户外2h + 为什么 + 和小朋友玩</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">回顾全程 🎯</p><p>每个阶段的&quot;算法&quot;都指向同一件事：<strong>不是加速发展，而是不错过窗口期</strong>。大自然已经写好了程序，你只需要提供环境和陪伴。</p></div>`,29)])])}const b=a(o,[["render",i]]);export{u as __pageData,b as default};
